create table dirkspzm32.cal_res_appointment_types (
    id                      number(*, 0) not null enable,
    cal_resource_id         number(*, 0) not null enable,
    cal_appointment_type_id number(*, 0) not null enable,
    name                    varchar2(50 char) not null enable
);

alter table dirkspzm32.cal_res_appointment_types
    add constraint pk_cal_res_app_types_id primary key ( id )
        using index enable;


